from langchain_core.tools import tool
from langchain_openai import ChatOpenAI
from langgraph.prebuilt import create_react_agent

@tool
def get_weather(city: str) -> str:
    """Return current weather for a city."""
    data = {"London": "12C, overcast", "Tokyo": "28C, sunny"}
    return data.get(city, "Weather data unavailable")

@tool
def convert_currency(amount: float, from_currency: str, to_currency: str) -> str:
    """Convert an amount between currencies at a fixed illustrative rate."""
    rates = {("USD", "EUR"): 0.92, ("EUR", "USD"): 1.09}
    rate = rates.get((from_currency, to_currency))
    if rate is None:
        return "Conversion rate not available"
    return f"{amount * rate:.2f} {to_currency}"

llm = ChatOpenAI(model="claude-sonnet-5", temperature=0)
agent = create_react_agent(llm, tools=[get_weather, convert_currency])

result = agent.invoke(
    {"messages": [{"role": "user", "content": "What's the weather in London and what is 100 USD in EUR?"}]}
)
print(result["messages"][-1].content)

from langchain.callbacks.base import BaseCallbackHandler
from langchain_core.outputs import LLMResult
import logging

logger = logging.getLogger(__name__)

class AugmentationLogger(BaseCallbackHandler):
    def on_retriever_end(self, documents, **kwargs):
        logger.info("Retrieved %d chunks", len(documents))
        for i, doc in enumerate(documents):
            logger.debug("  chunk[%d] score=%.3f text=%s...", i, doc.metadata.get("score", 0), doc.page_content[:80])

    def on_tool_start(self, serialized, input_str, **kwargs):
        logger.info("Tool call: %s input=%s", serialized.get("name"), input_str[:200])

    def on_tool_end(self, output, **kwargs):
        logger.info("Tool result: %s", str(output)[:200])

    def on_llm_end(self, response: LLMResult, **kwargs):
        usage = response.llm_output.get("token_usage", {})
        logger.info("LLM tokens: prompt=%d completion=%d",
                    usage.get("prompt_tokens", 0),
                    usage.get("completion_tokens", 0))

# Pass to any chain or agent
agent = create_react_agent(llm, tools=[...], callbacks=[AugmentationLogger()])
